static void flushed_printf(const char* format, ...) {
    va_list args;
    va_start(args, format);
    vprintf(format, args);
    va_end(args);
    fflush(stdout);
}

static void show_progress_init(int length) {
    flushed_printf("[");
    for (int i = 0; i < length; i++) flushed_printf(" ");
    flushed_printf("]");
    for (int i = 0; i <= length; i++) flushed_printf("\b");
}

static void show_progress_step(int domove, char newchar) {
    flushed_printf("%c", newchar);
    if (!domove) flushed_printf("\b");
}

static void show_progress_done(void) {
    flushed_printf("\n");
}

static double get_time_ms() {
    using clock = std::chrono::steady_clock;
    auto now = clock::now().time_since_epoch();
    return std::chrono::duration<double, std::milli>(now).count();
}

template <int N, typename F>
static double benchmark(F&& func) {
    double best = std::numeric_limits<double>::max();
    for (int i = 0; i < N; i++) {
        double v = func();
        if (v < best) best = v;
    }
    return best;
}

template <typename T>
struct DeviceOps;

template <>
struct DeviceOps<float> {
    __device__ static inline float zero() { return 0.0f; }
    __device__ static inline float minus_one() { return -1.0f; }
    __device__ static inline float add(float a, float b) { return a + b; }
    __device__ static inline float mul(float a, float b) { return a * b; }
    __device__ static inline bool is_equal(float a, float b) { return a == b; }
};

template <>
struct DeviceOps<double> {
    __device__ static inline double zero() { return 0.0; }
    __device__ static inline double minus_one() { return -1.0; }
    __device__ static inline double add(double a, double b) { return a + b; }
    __device__ static inline double mul(double a, double b) { return a * b; }
    __device__ static inline bool is_equal(double a, double b) { return a == b; }
};

template <>
struct DeviceOps<int> {
    __device__ static inline int zero() { return 0; }
    __device__ static inline int minus_one() { return -1; }
    __device__ static inline int add(int a, int b) { return a + b; }
    __device__ static inline int mul(int a, int b) { return a * b; }
    __device__ static inline bool is_equal(int a, int b) { return a == b; }
};

template <>
struct DeviceOps<__half2> {
    __device__ static inline __half2 zero() { return __float2half2_rn(0.0f); }
    __device__ static inline __half2 minus_one() { return __float2half2_rn(-1.0f); }
    __device__ static inline __half2 add(__half2 a, __half2 b) { return __hadd2(a, b); }
    __device__ static inline __half2 mul(__half2 a, __half2 b) { return __hmul2(a, b); }
    __device__ static inline bool is_equal(__half2 a, __half2 b) {
        return __half2float(__low2half(a)) == __half2float(__low2half(b)) &&
               __half2float(__high2half(a)) == __half2float(__high2half(b));
    }
};

template <typename T, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED>
__global__ void benchmark_func(T seed, T* g_data, int compute_iters, long logical_num_groups, long size) {
    const unsigned int blockSize = blockDim.x;

    long stride, idx;
    if (BLOCK_STRIDED) {
        stride = (long)blockSize;
        idx = (long)blockIdx.x * blockSize * ELEMENTS_PER_THREAD + threadIdx.x;
    } else {
        const long grid_size = (long)blockSize * logical_num_groups;
        stride = grid_size;
        idx = (long)blockIdx.x * blockSize + threadIdx.x;
    }
    const long big_stride = logical_num_groups * (long)blockSize * ELEMENTS_PER_THREAD;

    if (idx >= size) return;
    if (idx + (long)(FUSION_DEGREE - 1) * big_stride >= size) return;
    if (idx + (long)(ELEMENTS_PER_THREAD - 1) * stride +
            (long)(FUSION_DEGREE - 1) * big_stride >= size)
        return;

    T tmps[ELEMENTS_PER_THREAD];

    #pragma unroll
    for (int k = 0; k < FUSION_DEGREE; k++) {
        #pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + (long)j * stride + (long)k * big_stride];
            for (int i = 0; i < compute_iters; i++) {
                tmps[j] = DeviceOps<T>::add(DeviceOps<T>::mul(tmps[j], tmps[j]), seed);
            }
        }

        T sum = DeviceOps<T>::zero();
        #pragma unroll
        for (int j = 0; j + 1 < ELEMENTS_PER_THREAD; j += 2) {
            sum = DeviceOps<T>::add(sum, DeviceOps<T>::mul(tmps[j], tmps[j + 1]));
        }

        if (DeviceOps<T>::is_equal(sum, DeviceOps<T>::minus_one())) {
            g_data[idx + (long)k * big_stride] = sum;
        }
    }
}

template <typename T, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED>
static double launch_kernel_timed(
    T seed,
    void* buffer,
    long size,
    size_t workgroupsize,
    int compute_iters,
    bool use_os_timer,
    long total_threads_override = -1) {
    const long total_threads = (total_threads_override > 0)
                                   ? total_threads_override
                                   : (size / ELEMENTS_PER_THREAD / FUSION_DEGREE);
    const long logical_num_groups = total_threads / (long)workgroupsize;

    dim3 block((unsigned int)workgroupsize);
    dim3 grid((unsigned int)logical_num_groups);

    if (use_os_timer) {
        double ts_start = get_time_ms();
        benchmark_func<T, ELEMENTS_PER_THREAD, FUSION_DEGREE, BLOCK_STRIDED>
            <<<grid, block>>>(seed, reinterpret_cast<T*>(buffer), compute_iters, logical_num_groups, size);
        CUDA_SAFE_CALL(cudaGetLastError());
        CUDA_SAFE_CALL(cudaDeviceSynchronize());
        return get_time_ms() - ts_start;
    } else {
        cudaEvent_t ev_start, ev_stop;
        CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
        CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
        CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
        benchmark_func<T, ELEMENTS_PER_THREAD, FUSION_DEGREE, BLOCK_STRIDED>
            <<<grid, block>>>(seed, reinterpret_cast<T*>(buffer), compute_iters, logical_num_groups, size);
        CUDA_SAFE_CALL(cudaGetLastError());
        CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
        CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
        float ms = 0.0f;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
        return (double)ms;
    }
}

static void runbench_warmup(void* cbuffer, long size, size_t workgroupsize) {
    const long reduced_grid_size = size / 256;
    const short seed = 1;
    (void)launch_kernel_timed<short, 1, 1, false>(
        seed, cbuffer, size, workgroupsize, 0, false, reduced_grid_size);
}

static void runbench(const int compute_iterations_arr[],
                     unsigned int krn_idx,
                     void* cbuffer,
                     long size,
                     size_t workgroupsize,
                     unsigned int elements_per_wi,
                     unsigned int fusion_degree,
                     bool use_os_timer,
                     bool enable_dp,
                     bool enable_hp,
                     bool block_strided) {
    (void)elements_per_wi;
    (void)fusion_degree;

    const long compute_grid_size = size / 8 / 4;
    const int current_compute_iterations = compute_iterations_arr[krn_idx];
    const long long computations =
        (8LL * (long long)compute_grid_size +
         (2LL * 8LL * current_compute_iterations) * (long long)compute_grid_size) *
        4LL;
    const long long memoryoperations = size;

    constexpr auto total_bench_iterations = 3;

    double kernel_time_mad_sp = benchmark<total_bench_iterations>([&]() {
        const float seed_f = 1.0f;
        if (block_strided) {
            return launch_kernel_timed<float, 8, 4, true>(
                seed_f, cbuffer, size, workgroupsize, current_compute_iterations, use_os_timer);
        } else {
            return launch_kernel_timed<float, 8, 4, false>(
                seed_f, cbuffer, size, workgroupsize, current_compute_iterations, use_os_timer);
        }
    });

    double kernel_time_mad_dp = benchmark<total_bench_iterations>([&]() {
        const double seed_d = 1.0;
        if (!enable_dp) return 0.0;
        if (block_strided) {
            return launch_kernel_timed<double, 8, 4, true>(
                seed_d, cbuffer, size, workgroupsize, current_compute_iterations, use_os_timer);
        } else {
            return launch_kernel_timed<double, 8, 4, false>(
                seed_d, cbuffer, size, workgroupsize, current_compute_iterations, use_os_timer);
        }
    });

    double kernel_time_mad_hp = benchmark<total_bench_iterations>([&]() {
        const __half2 seed_h = __float2half2_rn(1.0f);
        if (!enable_hp) return 0.0;
        if (block_strided) {
            return launch_kernel_timed<__half2, 8, 4, true>(
                seed_h, cbuffer, size, workgroupsize, current_compute_iterations, use_os_timer);
        } else {
            return launch_kernel_timed<__half2, 8, 4, false>(
                seed_h, cbuffer, size, workgroupsize, current_compute_iterations, use_os_timer);
        }
    });

    double kernel_time_mad_int = benchmark<total_bench_iterations>([&]() {
        const int seed_i = 1;
        if (block_strided) {
            return launch_kernel_timed<int, 8, 4, true>(
                seed_i, cbuffer, size, workgroupsize, current_compute_iterations, use_os_timer);
        } else {
            return launch_kernel_timed<int, 8, 4, false>(
                seed_i, cbuffer, size, workgroupsize, current_compute_iterations, use_os_timer);
        }
    });

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations) / kernel_time_mad_dp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)2 * computations) /
            ((double)memoryoperations * sizeof(__half2)),
        kernel_time_mad_hp,
        ((double)2 * computations) / kernel_time_mad_hp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp *
            1000. / (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int,
        ((double)computations) / kernel_time_mad_int * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
            (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
    const bool block_strided = false;
    const bool host_allocated = false;
    const bool use_os_timer = false;
    const size_t workgroupsize = 256;
    const unsigned int elements_per_wi = 8;
    const unsigned int fusion_degree = 4;

    const char* benchtype = block_strided ? "Workgroup" : "NDRange";
    printf("Workitem stride:        %s\n", benchtype);
    const char* buffer_allocation =
        host_allocated ? "Host allocated" : "Device allocated";
    printf("Buffer allocation:      %s\n", buffer_allocation);
    printf("Timer:                  %s\n",
           use_os_timer ? "OS based" : "CL event based");
    printf("Workgroup size:         %d\n", (int)workgroupsize);
    printf("Elements per workitem:  %d\n", elements_per_wi);
    printf("Workitem fusion degree: %d\n", fusion_degree);

    const bool enable_dp = true;
    const bool enable_hp = IsFP16Supported();
    if (!enable_hp) {
        printf(
            "Warning:                Half precision computations are not "
            "supported\n");
    }

    void* c_buffer = nullptr;
    CUDA_SAFE_CALL(cudaMalloc(&c_buffer, (size_t)size * sizeof(double)));

    CUDA_SAFE_CALL(cudaMemset(c_buffer, 0, (size_t)size * sizeof(int)));

    printf("Loading kernel source file...\n");
    printf("Precompilation of kernels... ");
    show_progress_init(compute_iterations_len);
    for (int i = 0; i < compute_iterations_len; i++) {
        show_progress_step(0, '\\');
        show_progress_step(0, '|');
        if (enable_dp) show_progress_step(0, '/');
        if (enable_hp) show_progress_step(0, '-');
        show_progress_step(1, '>');
    }
    show_progress_done();

    runbench_warmup(c_buffer, size, workgroupsize);

    CUDA_SAFE_CALL(cudaDeviceSynchronize());

    printf(
        "------------------------------------------------------------------------"
        "----- CSV data "
        "------------------------------------------------------------------------"
        "-----\n");
    printf(
        "Experiment ID, Single Precision ops,,,,              Double precision "
        "ops,,,,              Half precision ops,,,,                Integer "
        "operations,,, \n");
    printf(
        "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
        "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
        "Iops/byte, ex.time,   GIOPS, GB/sec\n");

    for (int i = 0; i < compute_iterations_len; i++) {
        runbench(compute_iterations, i, c_buffer, size, workgroupsize,
                 elements_per_wi, fusion_degree, use_os_timer,
                 enable_dp, enable_hp, block_strided);
    }

    printf(
        "------------------------------------------------------------------------"
        "------------------------------------------------------------------------"
        "--------------------\n");

    CUDA_SAFE_CALL(cudaMemcpy(c, c_buffer, (size_t)size * sizeof(double),
                              cudaMemcpyDeviceToHost));

    CUDA_SAFE_CALL(cudaFree(c_buffer));
}
